import Marquee from "react-fast-marquee";
import { motion } from "framer-motion";

const MovingGallery = () => {
  const videoSources = [
    "/assets/videos/cooking.mp4",
    "/assets/videos/vid2.mp4",
    "/assets/videos/vid3.mp4",
    "/assets/videos/vid5.mp4",
    "/assets/videos/vid6.mp4"
  ];

  const imageSources = [
    "/assets/amb.jpg",
    "/assets/apr.jpg",
    "/assets/ballent.jpg",
    "/assets/bl.jpg",
    "/assets/bn.jpg",
    "/assets/dj.jpg",
    "/assets/dri.jpg",
    "/assets/f1.jpg",
    "/assets/grp.jpg",
    "/assets/nod.jpg",
    "/assets/pic.jpg",
    "/assets/piz.jpg"
  ];

  return (
    <section className="w-full py-20 bg-black/95 overflow-hidden">
      {/* Title */}
      <div className="text-center mb-20">
        <motion.span 
          initial={{ opacity: 0 }}
          whileInView={{ opacity: 1 }}
          className="inline-block text-gold text-sm font-bold tracking-[0.2em] uppercase px-6 py-2 border-2 border-gold rounded-full"
        >
          Gallery
        </motion.span>
        <motion.h2 
          initial={{ opacity: 0, y: 20 }}
          whileInView={{ opacity: 1, y: 0 }}
          className="text-4xl md:text-5xl font-bold text-white mt-6"
        >
          Corridor Moments
        </motion.h2>
      </div>

      {/* Video Marquee - ZERO GAP FIX */}
      <div className="w-[200vw] bg-black">
        <Marquee speed={18} gradient={false} pauseOnHover={true}>
          {[...videoSources, ...videoSources].map((src, index) => (
            <video
              key={index}
              src={src}
              className="ml-[2px] w-[200px] h-[340px] object-cover rounded-xl shadow-[0_20px_40px_rgba(0,0,0,.8)] border border-black"
              muted
              autoPlay
              loop
              playsInline
              preload="auto"
            />
          ))}
        </Marquee>
      </div>

      {/* Images Marquee 1 - LTR - ZERO GAP */}
      <div className="mt-16">
        <Marquee speed={55} gradient={false} pauseOnHover={true}>
          {imageSources.slice(0,11).map((src, index) => (
            <motion.img
              key={index}
              src={src}
              className="ml-[1px] w-[270px] h-[190px] object-cover rounded-lg shadow-lg border border-black grayscale hover:grayscale-0 hover:shadow-2xl hover:scale-105 transition-all duration-300"
              loading="eager"
            />
          ))}
        </Marquee>
      </div>

      {/* Images Marquee 2 - RTL - ZERO GAP */}
      <div className="mt-8">
        <Marquee speed={55} direction="right" gradient={false} pauseOnHover={true}>
          {imageSources.slice(0,9).map((src, index) => (
            <motion.img
              key={`rtl-${index}`}
              src={src}
              className="ml-[1px] w-[270px] h-[190px] object-cover rounded-lg shadow-lg border border-black grayscale hover:grayscale-0 hover:shadow-2xl hover:scale-105 transition-all duration-300"
              loading="eager"
            />
          ))}
        </Marquee>
      </div>
    </section>
  );
};

export default MovingGallery;
